@startuml

abstract class WordFinder {
  fileCreator()
  replaceInString()
}

class String {
  revised
  content
  file
  str
  --
  replaceAll()
}

class PrintWriter {
  out
  writer
  --
  close()
  println()
}

class Files {
  readString
}

class Scanner {
  input
  --
  nextLine()
}

WordFinder <|-- WordFinder
String <-- WordFinder
PrintWriter --> WordFinder
Files --> WordFinder
Scanner --> WordFinder

@enduml
